const body = $input.first().json.body || {};
return [{
  json: {
    content: body.content || '',
    etp_content: body.etp_content || 'Nenhum ETP fornecido.',
    matriz_riscos: body.matriz_riscos || 'Nenhuma Matriz de Risco fornecida.',
    process_id: body.process_id || 'N/A',
    has_file: body.has_file === 'true' || body.has_file === true
  }
}];

function extractJSON(text) {
  if (!text || typeof text !== 'string') {
    if (typeof text === 'object' && text !== null) return text;
    return {};
  }
  try {
    const mdMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (mdMatch) return JSON.parse(mdMatch[1]);
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
  } catch (e) {}
  return { output_falho: text };
}

// With Merge (Append), items are in order: Agent1, Agent2, Agent3
const items = $input.all();
const out1 = extractJSON(items[0]?.json?.output);
const out2 = extractJSON(items[1]?.json?.output);
const out3 = extractJSON(items[2]?.json?.output);

const processId = $('Processa Payload').first().json.process_id || 'N/A';

// Build preview text for UI
const previewRequisitos = out2.secao_requisitos_texto || out2.output_falho || '';
const previewGestao = out3.secao_gestao_texto || out3.output_falho || '';
const previewInfracoes = out3.secao_infracoes_texto || '';

// Build the exact docxtemplater JSON matching the tagged template
const docxData = {
  // Agente 1
  numero_processo: processId,
  objeto_contratacao: out1.objeto_contratacao || 'N/A',
  atividades_incluidas: out1.atividades_incluidas || '',
  prazo_entrega: out1.prazo_entrega || 'N/A',
  prazo_vigencia: out1.prazo_vigencia || 'N/A',
  ano_pca: out1.ano_pca || new Date().getFullYear().toString(),
  itens: Array.isArray(out1.itens) ? out1.itens : [],

  // Agente 2
  is_bens_comuns: out2.is_bens_comuns !== undefined ? out2.is_bens_comuns : true,
  is_bens_especiais: out2.is_bens_especiais !== undefined ? out2.is_bens_especiais : false,
  aceita_subcontratacao: out2.aceita_subcontratacao !== undefined ? out2.aceita_subcontratacao : false,
  percentual_subcontratacao: out2.percentual_subcontratacao || 0,
  exige_amostra: out2.exige_amostra !== undefined ? out2.exige_amostra : false,
  exige_garantia_contratual: out2.exige_garantia_contratual !== undefined ? out2.exige_garantia_contratual : false,
  percentual_garantia: out2.percentual_garantia || 5,
  modalidade_licitacao: out2.modalidade_licitacao || 'Pregão Eletrônico',

  // Agente 3
  prazo_garantia: out3.prazo_garantia || '12 meses',
  tem_garantia_contratual: out3.tem_garantia_contratual !== undefined ? out3.tem_garantia_contratual : false
};

return [{
  json: {
    sucesso: true,
    frontend_preview: {
      secao_requisitos: previewRequisitos,
      secao_gestao: previewGestao,
      secao_infracoes: previewInfracoes
    },
    docxtemplater: docxData
  }
}];
